DROP TABLE IF EXISTS `qa_sys`;
CREATE TABLE `qa_sys`  (
  `record_id` varchar(40) CHARACTER SET utf8 COLLATE utf8_unicode_ci NOT NULL COMMENT '记录ID',
  `create_by` varchar(40) CHARACTER SET utf8 COLLATE utf8_unicode_ci NULL DEFAULT NULL COMMENT '创建问题用户名',
