  `update_id` varchar(50) CHARACTER SET utf8 COLLATE utf8_unicode_ci NULL DEFAULT NULL COMMENT '回答问题用户工号',
  `update_time` datetime(0) NULL DEFAULT NULL COMMENT '更新时间',
